// build.gradle (Module: app)
dependencies {
    implementation 'com.squareup.okhttp3:okhttp:4.9.1'
    implementation 'com.squareup.retrofit2:retrofit:2.9.0'
    implementation 'com.squareup.retrofit2:converter-gson:2.9.0'
}

// NetworkingModule.kt
import okhttp3.Interceptor
import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory

object NetworkingModule {
    private const val BASE_URL_DEV = "https://api.example.com/dev/users/"
    private const val BASE_URL_STAGING = "https://api.example.com/staging/users/"
    private const val BASE_URL_PRODUCTION = "https://api.example.com/users/"

    fun createService(environment: Environment, authToken: String): UserService {
        val httpClient = OkHttpClient.Builder()
            .addInterceptor { chain ->
                val originalRequest = chain.request()
                val requestBuilder = originalRequest.newBuilder()
                    .header("Authorization", "Bearer $authToken")
                chain.proceed(requestBuilder.build())
            }
            .build()

        val retrofit = Retrofit.Builder()
            .baseUrl(getBaseUrl(environment))
            .client(httpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()

        return retrofit.create(UserService::class.java)
    }

    private fun getBaseUrl(environment: Environment): String {
        return when (environment) {
            Environment.DEV -> BASE_URL_DEV
            Environment.STAGING -> BASE_URL_STAGING
            Environment.PRODUCTION -> BASE_URL_PRODUCTION
        }
    }
}

enum class Environment {
    DEV,
    STAGING,
    PRODUCTION
}

// UserService.kt
interface UserService {
    @GET("profile/{userId}")
    suspend fun getUserProfile(@Path("userId") userId: String): UserProfile

    data class UserProfile(
        val id: Int,
        val name: String,
        val email: String
    )
}